add_action( 'wp_enqueue_scripts', 'upload_files' );
function upload_files() {
    wp_register_script('upload-js', plugins_url('/js/upload.js', __FILE__));
    wp_enqueue_script('upload-js');

    wp_register_style('upload-css', plugins_url('/css/upload.css', __FILE__));
    wp_enqueue_style('upload-css');
}
add_action( 'admin_menu', 'upload_files_admin' );
function upload_files_admin() {
    add_options_page(
        'Upload Files Options', 
        'Upload Files', 
        'manage_options', 
        'upload-files', 
        'upload_files_options');
}
add_action('wp_ajax_upload_file', 'upload_file');
function upload_file() {
    $allowed = array( 'jpg' => 'image/jpeg', 'png' => 'image/png', 'pdf' => 'application/pdf', 'doc' => 'application/msword', 'docx' => 'application/vnd.openxmlformats-officedocument.wordprocessingml.document');
    $file = $_FILES['file'];

    if(isset($allowed[$file['type']])) {
        move_uploaded_file($file["tmp_name"], plugin_dir_path(__FILE__) . "uploads/" . $file["name"]);
        echo json_encode(['status' => 'success', 'message' => 'File uploaded successfully.']);
    } else {
        echo json_encode(['status' => 'error', 'message' => 'Invalid file type.']);
    }

    wp_die();
}
function upload_files_options() { ?>
    <div class="wrap">
        <h1>Upload Files</h1>
        <?php settings_errors(); ?>
        <form method="post" action="options.php">
            <?php
                settings_fields('upload-files');
                do_settings_sections( 'upload-files' );
                submit_button(); 
            ?>
        </form>
    </div>
<?php }
add_action('admin_init', 'upload_files_register_settings');
function upload_files_register_settings() {
    register_setting('upload-files', 'upload-files');

    add_settings_section( 
        'upload-files-section',
        __('Upload Files Options'),
        '',
        'upload-files' 
    );

    add_settings_field( 
        'upload-files-option1',
        __('Option 1'),
        'upload_files_option1_callback',
        'upload-files',
        'upload-files-section');
}
function upload_files_option1_callback() {
    $options = get_option('upload-files'); ?>

    <input type="text" name="upload-files[upload-files-option1]" value="<?php echo esc_attr($options['upload-files-option1']); ?>" />
<?php }